const rows = $input.all();
function valid(v){const p=String(v).trim().split('.');return p.length===4&&p.every(x=>/^\d{1,3}$/.test(x)&&Number(x)>=0&&Number(x)<=255);}
const seen=new Set(), out=[], rejected=[];
for(const row of rows){const raw=row.json.ip??row.json.IP??row.json.address??row.json.ip_address;
 if(raw===undefined||raw===null||String(raw).trim()===''){rejected.push({value:raw??'',reason:'Missing IP value'});continue;}
 const ip=String(raw).trim(); if(!valid(ip)){rejected.push({value:ip,reason:'Invalid IPv4 address'});continue;}
 if(seen.has(ip)){rejected.push({value:ip,reason:'Duplicate'});continue;} seen.add(ip); out.push({json:{ip,rejectedRows:rejected}});}
if(!out.length) throw new Error('No valid IPv4 addresses found. Use a CSV column named ip.'); return out;

const responses=$input.all(); const requests=$('Validate and Deduplicate IPs').all();
const findings=responses.map((item,i)=>{const ip=requests[i]?.json?.ip??null; const r=item.json??{}; const status=r.statusCode??200; const b=r.body??r;
 if(status===404)return{ip,found:false,statusCode:status,ports:[],hostnames:[],cpes:[],vulnerabilities:[],tags:[],message:'No InternetDB record found.'};
 if(status<200||status>=300)return{ip,found:false,statusCode:status,ports:[],hostnames:[],cpes:[],vulnerabilities:[],tags:[],message:b?.detail??b?.error??`Lookup failed with HTTP ${status}.`};
 return{ip:b.ip??ip,found:true,statusCode:status,ports:Array.isArray(b.ports)?b.ports:[],hostnames:Array.isArray(b.hostnames)?b.hostnames:[],cpes:Array.isArray(b.cpes)?b.cpes:[],vulnerabilities:Array.isArray(b.vulns)?b.vulns:[],tags:Array.isArray(b.tags)?b.tags:[]};});
return[{json:{generatedAt:new Date().toISOString(),source:'Shodan InternetDB',sourceNote:'Summarized data; full service banners are not included.',requestedCount:requests.length,foundCount:findings.filter(x=>x.found).length,notFoundOrFailedCount:findings.filter(x=>!x.found).length,rejectedRows:requests[0]?.json?.rejectedRows??[],findings}}];

